var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"벌써 휴가도 마지막 날이네.","JPN":"もうこの旅も最終日か。","ENG":"It's already the last day of our vacation.","TWN":"好快喔，今天已經是假期最後一天。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"아쉽다……. 시간이 금방 지나갔어.","JPN":"さみしいな……時間があっという間に過ぎちゃった。","ENG":"Aw… Time sure flies when you're having fun.","TWN":"真捨不得……時間怎麼過這麼快～"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"마지막 날이니 오늘 밤은 더 원없이 즐겨.","JPN":"最終日だから今夜は好きなだけ楽しんでいいよ。","ENG":"Indulge yourself tonight, since this is the last day.","TWN":"既然是最後一天，那我們更要盡情享受最後一晚。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그래야 자기랑 같이 온 나도 만족할 수 있으니까.","JPN":"ハニーの喜ぶ姿が僕にとって一番の幸せだから。","ENG":"Nothing would satisfy more than you really enjoying yourself here.","TWN":"這樣才不枉費和親愛的一起來玩。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자기 일은 좀 어때? 계속 통화하는 것 같던데, 잘 해결됐어?","JPN":"ダーリンの仕事はどう？　ずっと通話していたけど、ちゃんと解決できたの？","ENG":"How's your work going, babe? You seem to be on the phone a lot… Did everything work out?","TWN":"親愛的事呢？我看你好像一直在講電話，事情還順利嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"아, 그럼. 물론이지. 도시 관리국에 있는 지인한테 부탁했으니까.","JPN":"ああ、もちろん。都市管理局の知り合いに頼んでおいたからね。","ENG":"Oh, yes. Of course. I called in a favor with someone at the City Managements.","TWN":"喔～那當然，我有拜託城市管理局的好朋友處理。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"도시 관리국에? 어떤 사람이야? 혹시 나도 알 만큼 높은 사람?","JPN":"都市管理局に？　どんな人？　私も知っているぐらい偉い人？","ENG":"The City Managements? Who is it? Someone famous enough for me to recognize?","TWN":"城市管理局嗎？誰啊？是我也認識的人嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그렇게 대단한 사람은 아니고 말이 좀 통할 뿐이야. 사업하다가 알게 됐거든.","JPN":"そこまでお偉いさんではないけど、まあまあ話が通じる人さ。仕事で知り合ったんだ。","ENG":"No, it's not a big shot like that. We just click well. A former business associate.","TWN":"不是什麼大人物啦，只是個聊得來的朋友，是做生意的時候認識的。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"굉장하다…… 난 스튜어디스 일 할 때도 그런 사람들 못 만나 봤는데.","JPN":"すごい……私はCA時代でさえそんな凄い人に会ったことないのに。","ENG":"That's amazing… I never got to see anyone that important, even when I was working as a flight attendant.","TWN":"好厲害喔……我在飛機上服務客人時，也沒見過那種大人物呢～"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"신경 쓰지 마. 앞으로는 질리도록 만나게 될 테니까.","JPN":"気にするな。これからは飽きるほど会うことになるからさ。","ENG":"Don't let that bother you. You'll be mingling with no one but big shots from now on.","TWN":"沒什麼啦，以後見面次數可能會多到很煩呢。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그래, 어디 보자. 관리국이라면 돈만 빨아먹는 타격조 놈들보다는 잘 처리했겠지.","JPN":"さてと、どれどれ。管理局なら金だけ吸い取る突撃隊よりはうまく対応してくれただろうな。","ENG":"Let's see… I'm sure the Administration would have done a better job than those money-sucking strike squads.","TWN":"我來看看～ 管理局應該會處理得比那些視錢如命的打擊組好吧？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"지금쯤이면 붙잡혀서 슈퍼맥스급 교도소로 갔거나, 기계인 게 탄로나서……","JPN":"今頃連行されてスーパーマックス級の刑務所に送られたか、機械ってことがバレて……","ENG":"By now, she's probably locked up in a supermax prison or exposed as a machine…","TWN":"現在要嘛被抓去監獄關，要嘛機器人的身分曝光……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자기야, 저기 봐!","JPN":"ダーリン、あれを見て！","ENG":"Babe, look!","TWN":"親愛的，你看那邊！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"하하, 그렇게 갑자기 안기면 놀란다니까.","JPN":"ハハ、そんな急に抱きついて来たらビックリするだろ。","ENG":"Haha, I told you I get jumpy if you hug me so suddenly.","TWN":"哈哈，你突然這樣抱住我，嚇我一跳呢～"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그런데 왜 그래? 하늘에 뭐가 있는데?","JPN":"どうしたんだ？　空に何かあるのかい？","ENG":"Anyway, what is it? Is there something up in the sky?","TWN":"是怎麼了嗎？ 空中有什麼嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"비행기야! 저기 연기 보여?","JPN":"飛行機よ！　あの煙、すご～い！","ENG":"It's a plane! See that smoke?","TWN":"飛機欸！你有看到白煙嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"이 호텔은 밤에 에어쇼도 해 주나 봐. 마지막 날까지 정말 최고야…….","JPN":"このホテルは夜にエアショーもやるのね。旅の最終日まで本当に最高！","ENG":"This hotel must put on airshows too. Even at night! It's perfect to the very last day…","TWN":"這個飯店晚上還有飛行表演呢，真是完美的最後一夜……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"잠깐만, 저 연기는 일부러 피워 올리는 게 아닌 것 같은데……?","JPN":"待って、あの煙はわざわざショーのために作ったものじゃないような……？","ENG":"Hang on… That smoke doesn't look like it's for show…","TWN":"等等，那個白煙似乎不是刻意的……？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};